package org.example.security;
import jakarta.servlet.*; import jakarta.servlet.http.*; import org.springframework.security.authentication.UsernamePasswordAuthenticationToken; import org.springframework.security.core.context.SecurityContextHolder; import org.springframework.security.core.userdetails.*; import org.springframework.security.web.authentication.WebAuthenticationDetailsSource; import org.springframework.stereotype.Component; import org.springframework.web.filter.OncePerRequestFilter; import java.io.IOException;
@Component public class JwtAuthenticationFilter extends OncePerRequestFilter { private final JwtService jwtService; private final UserDetailsService uds; public JwtAuthenticationFilter(JwtService jwtService, UserDetailsService uds){this.jwtService=jwtService;this.uds=uds;} protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain chain) throws ServletException, IOException { String header=request.getHeader("Authorization"); if(header==null||!header.startsWith("Bearer ")){chain.doFilter(request,response);return;} String token=header.substring(7); try { String username=jwtService.extractUsername(token); if(username!=null && SecurityContextHolder.getContext().getAuthentication()==null){ UserDetails userDetails=uds.loadUserByUsername(username); if(jwtService.isTokenValid(token,userDetails)){ UsernamePasswordAuthenticationToken auth=new UsernamePasswordAuthenticationToken(userDetails,null,userDetails.getAuthorities()); auth.setDetails(new WebAuthenticationDetailsSource().buildDetails(request)); SecurityContextHolder.getContext().setAuthentication(auth); } } } catch(Exception ex){ SecurityContextHolder.clearContext(); } chain.doFilter(request,response); } }
